export const VIETNAMESE_EVENTS = {
    CARD_FLIPPED: 'vietnamese:card-flipped',
} as const;

export interface VietnameseEventMap {
    [VIETNAMESE_EVENTS.CARD_FLIPPED]: undefined;
}

export type VietnameseEvent<K extends keyof VietnameseEventMap> = CustomEvent<VietnameseEventMap[K]>;

export function createVietnameseEvent<K extends keyof VietnameseEventMap>(
    type: K,
    detail: VietnameseEventMap[K]
): VietnameseEvent<K> {
    return new CustomEvent(type, {
        bubbles: true,
        composed: true,
        detail,
    }) as VietnameseEvent<K>;
}

export const createCardFlippedEvent = () => createVietnameseEvent(VIETNAMESE_EVENTS.CARD_FLIPPED, undefined);

export type CardFlippedEvent = VietnameseEvent<typeof VIETNAMESE_EVENTS.CARD_FLIPPED>;

declare global {
    interface HTMLElementEventMap {
        [VIETNAMESE_EVENTS.CARD_FLIPPED]: CardFlippedEvent;
    }
}
