import { buildSectionPage } from '../../utils/section-page.utils.js';
import './review-session/review-session.component.js';
import type { ReviewSession } from './review-session/review-session.component.js';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../_shared/screen-status.js';

export class VietnameseReviewScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private reviewSession: ReviewSession | null = null;
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Learn', 'vietnamese', '/vietnamese');
        this.reviewSession = document.createElement('review-session') as ReviewSession;
        page.content.append(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode, this.reviewSession);
    }

    disconnectedCallback(): void {
        this.reviewSession?.remove();
        this.reviewSession = null;
    }
}

customElements.define('vietnamese-review-screen', VietnameseReviewScreen);
